#include <stdio.h>

int main() {
    int T; scanf("%d", &T);
    while (T--) {
        int N; scanf("%d", &N);
        int A[1005];
        for (int i = 1; i <= N; ++i) scanf("%d", &A[i]);
        int line[1005]; // current order, 0‑based
        int sz = 0; // current size of line
        long long steps = 0;
        for (int i = 1; i <= N; ++i) {
            int idx = -1; // index of A[i] in current line
            if (A[i] != 0) {
                for (int j = 0; j < sz; ++j) if (line[j] == A[i]) { idx = j; break; }
            }
            int pos = idx + 1; // insertion position
            int left = pos;
            int right = sz - pos;
            steps += left < right ? left : right;
            // shift to make room
            for (int j = sz; j > pos; --j) line[j] = line[j-1];
            line[pos] = i;
            ++sz;
        }
        printf("%lld\n", steps);
    }
    return 0;
}

