#include <bits/stdc++.h>
using namespace std;
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0;
    while(T--){
        int N; cin>>N;
        vector<int> A(N+1);
        for(int i=1;i<=N;++i) cin>>A[i];
        vector<int> line; line.reserve(N);
        long long steps=0;
        for(int i=1;i<=N;++i){
            int pos=0;
            if(A[i]!=0){
                auto it=find(line.begin(), line.end(), A[i]);
                pos = (int)(it - line.begin()) + 1;
            }
            int left=pos;
            int right=(int)line.size()-pos;
            steps+= min(left,right);
            line.insert(line.begin()+pos, i);
        }
        cout<<steps<<"\n";
    }
    return 0;
}

code.Java:
import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        while (T-- > 0) {
            int N = Integer.parseInt(br.readLine().trim());
            int[] A = new int[N+1];
            StringTokenizer st = new StringTokenizer(br.readLine());
            for (int i = 1; i <= N; i++) A[i] = Integer.parseInt(st.nextToken());
            List<Integer> line = new ArrayList<>(N);
            long steps = 0;
            for (int i = 1; i <= N; i++) {
                int pos = 0;
                if (A[i] != 0) {
                    pos = line.indexOf(A[i]) + 1; // indexOf returns -1 if not found, but A[i] always present
                }
                int left = pos;
                int right = line.size() - pos;
                steps += Math.min(left, right);
                line.add(pos, i);
            }
            out.append(steps).append('\n');
        }
        System.out.print(out.toString());
    }
}

