const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; ++t) {
  const N = Number(input[idx++]);
  const A = new Array(N + 1);
  for (let i = 1; i <= N; ++i) A[i] = Number(input[idx++]);
  const line = [];
  let steps = 0;
  for (let i = 1; i <= N; ++i) {
    let pos;
    if (A[i] === 0) {
      pos = 0;
    } else {
      pos = line.indexOf(A[i]) + 1;
    }
    const left = pos;
    const right = line.length - pos;
    steps += left < right ? left : right;
    line.splice(pos, 0, i);
  }
  outputs.push(String(steps));
}
